import java.util.Arrays;

public double trimmedMean(int[] arr) {
    int n = arr.length;
    int remove = (int) (n * 0.05);
    Arrays.sort(arr);
    double sum = 0.0;
    for (int i = remove; i < n - remove; i++) {
        sum += arr[i];
    }
    return sum / (n - 2 * remove);
}
```

